import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";
import type { Metadata } from "next";
import TwoFactorSetup from "@/components/dashboard/TwoFactorSetup";
import IntegrationsSettings from "@/components/dashboard/IntegrationsSettings";

export const metadata: Metadata = { title: "Configurações" };

export default async function ConfiguracoesPage() {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) redirect("/auth/login");

  const { data: therapist } = await supabase
    .from("therapists")
    .select("*")
    .eq("user_id", user.id)
    .single();
  if (!therapist) redirect("/auth/login");

  // Fetch MFA factors
  const { data: mfaData } = await supabase.auth.mfa.listFactors();
  const factors = (mfaData?.totp ?? []).map((f) => ({
    id: f.id,
    type: f.factor_type,
    status: f.status,
  }));

  return (
    <div className="w-full max-w-[1480px] mx-auto px-4 py-8 sm:px-8 lg:px-10 xl:px-12 animate-[fadeUp_.4s_ease-out_both]">
      {/* Header */}
      <div className="mb-8">
        <h1 className="font-[family-name:var(--font-display)] text-[36px] sm:text-[44px] lg:text-[52px] font-light text-[var(--color-text-primary)] tracking-tight leading-none">
          Configurações
        </h1>
        <p className="mt-2 text-[15px] font-light text-[var(--color-text-secondary)]">
          Perfil, integrações e segurança
        </p>
      </div>

      <div className="grid grid-cols-1 gap-6 xl:grid-cols-2">
        <div className="space-y-6">
          <div className="animate-[fadeUp_.4s_ease-out_.05s_both]">
            <Section title="Perfil Profissional" icon="👤">
              <InfoRow label="Nome" value={therapist.name} />
              <InfoRow label="CRP" value={therapist.crp} />
              <InfoRow label="Bio" value={therapist.bio ?? "Não definida"} />
              <InfoRow label="Slug" value={`/booking/${therapist.slug}`} mono />
              <InfoRow
                label="Especialidades"
                value={
                  therapist.specialties && (therapist.specialties as string[]).length > 0
                    ? (therapist.specialties as string[]).join(", ")
                    : "Nenhuma definida"
                }
              />
              <InfoRow label="Foto" value={therapist.photo_url ?? "Não definida"} isLast />
            </Section>
          </div>

          <div className="animate-[fadeUp_.4s_ease-out_.1s_both]">
            <Section title="Sessão" icon="🕐">
              <InfoRow
                label="Preço"
                value={`R$ ${Number(therapist.session_price).toFixed(2)}`}
                highlight
              />
              <InfoRow label="Duração" value={`${therapist.session_duration} minutos`} />
              <InfoRow label="Timezone" value={therapist.timezone} isLast />
            </Section>
          </div>
        </div>

        <div className="space-y-6">
          <div className="animate-[fadeUp_.4s_ease-out_.15s_both]">
            <Section title="Integrações" icon="🔗">
              <div className="p-1">
                <IntegrationsSettings
                  initialOpenRouter={therapist.openrouter_key_hash}
                  initialTelegram={therapist.telegram_bot_token}
                  initialStripe={therapist.stripe_account_id}
                  aiModel={therapist.ai_model}
                />
              </div>
            </Section>
          </div>

          <div className="animate-[fadeUp_.4s_ease-out_.2s_both]">
            <Section title="Segurança" icon="🔒">
              <InfoRow label="Email" value={user.email ?? "—"} />
              <InfoRow
                label="Último login"
                value={
                  user.last_sign_in_at
                    ? new Date(user.last_sign_in_at).toLocaleString("pt-BR")
                    : "—"
                }
              />
              <InfoRow label="Conta ativa" value={therapist.active ? "Sim" : "Não"} />
              <InfoRow
                label="Onboarding"
                value={therapist.onboarding_completed ? "Concluído ✅" : "Pendente"}
                isLast={factors.length === 0}
              />

              <div className="mt-5 border-t border-[var(--color-border-subtle)] pt-5 p-1">
                <TwoFactorSetup initialFactors={factors} />
              </div>
            </Section>
          </div>
        </div>
      </div>

      {/* Timestamps */}
      <div className="mt-8 flex flex-wrap gap-x-8 gap-y-2 rounded-xl border border-[var(--color-border-subtle)] bg-[var(--color-surface)] p-5 text-[11px] text-[var(--color-text-muted)] animate-[fadeUp_.4s_ease-out_.25s_both] glass-panel">
        <span>
          Conta criada:{" "}
          {new Date(therapist.created_at).toLocaleDateString("pt-BR")}
        </span>
        <span>
          Última atualização:{" "}
          {new Date(therapist.updated_at).toLocaleDateString("pt-BR")}
        </span>
      </div>
    </div>
  );
}

// ── Subcomponents ─────────────────────────────────────────────────
function Section({
  title,
  icon,
  children,
}: {
  title: string;
  icon: string;
  children: React.ReactNode;
}) {
  return (
    <div className="bg-[var(--color-surface)] border border-[var(--color-border-subtle)] rounded-3xl p-7 lg:p-8 glass-panel overflow-hidden transition-all duration-300 hover:border-[var(--color-border-strong)]">
      <h2 className="font-[family-name:var(--font-display)] text-[26px] font-light text-[var(--color-text-primary)] mb-5 flex items-center gap-3">
        <span className="text-[20px] opacity-80">{icon}</span> {title}
      </h2>
      <div className="flex flex-col gap-0 px-1">
        {children}
      </div>
    </div>
  );
}

function InfoRow({
  label,
  value,
  mono,
  highlight,
  isLast,
}: {
  label: string;
  value: string;
  mono?: boolean;
  highlight?: boolean;
  isLast?: boolean;
}) {
  return (
    <div
      className={`flex justify-between items-center py-3.5 transition-colors hover:bg-[var(--color-surface-hover)] rounded-lg px-3 -mx-3 ${
        isLast ? "" : "border-b border-[var(--color-border-subtle)]/50"
      }`}
    >
      <span className="text-[13px] uppercase tracking-[0.08em] text-[var(--color-text-muted)] font-medium">
        {label}
      </span>
      <span
        className={`text-[15px] text-right truncate max-w-[60%] sm:max-w-[70%] ${
          highlight ? "text-[#fbbf24] font-medium" : "text-[var(--color-text-primary)] font-light"
        } ${mono ? "font-mono text-[12px] opacity-80" : ""}`}
      >
        {value}
      </span>
    </div>
  );
}
